package com.example.mod;

import net.minecraftforge.common.MinecraftForge;
import net.minecraftforge.event.RegistryEvent.Register;
import net.minecraftforge.fml.common.Mod;
import net.minecraftforge.fml.event.lifecycle.FMLClientSetupEvent;
import net.minecraftforge.fml.event.lifecycle.FMLCommonSetupEvent;
import net.minecraftforge.fml.javafmlmod.FMLJavaModLoadingContext;

@Mod("miragemaison")
public class MirageMaison {
    public MirageMaison() {
        FMLJavaModLoadingContext.get().getModEventBus().addListener(this::setup);
        FMLJavaModLoadingContext.get().getModEventBus().addListener(this::doClientStuff);
        MinecraftForge.EVENT_BUS.register(this);
    }

    private void setup(final FMLCommonSetupEvent event) {
        // Initialization logic here
    }

    private void doClientStuff(final FMLClientSetupEvent event) {
        // Client-specific initialization logic here
    }

    @Mod.EventBusSubscriber(bus = Mod.EventBusSubscriber.Bus.MOD)
    public static class RegistrationEvents {
        @SubscribeEvent
        public static void registerBlocks(Register<Block> event) {
            event.getRegistry().registerAll(
                new EnchantedBookshelf()
            );
        }

        @SubscribeEvent
        public static void registerItems(Register<Item> event) {
            event.getRegistry().registerAll(
                new Item(new Item.Properties())
                    .setRegistryName("enchanted_bookshelf")
            );
        }
    }

    public static class EnchantedBookshelf extends Block {
        public EnchantedBookshelf() {
            super(Block.Properties.create(Material.WOOD).hardnessAndResistance(2.0f));
        }
    }
}
