package com.example.mod;

import net.minecraft.entity.player.EntityPlayer;
import net.minecraft.item.ItemStack;
import net.minecraft.nbt.NBTTagCompound;
import net.minecraft.util.EnumFacing;
import net.minecraft.util.math.BlockPos;
import net.minecraft.world.World;
import net.minecraftforge.event.entity.living.LivingUpdateEvent;
import net.minecraftforge.fml.common.Mod;
import net.minecraftforge.fml.common.eventhandler.SubscribeEvent;
import net.minecraftforge.fml.common.gameevent.PlayerEvent;

@Mod(modid = MercantileMasters.MODID, name = MercantileMasters.NAME, version = MercantileMasters.VERSION)
public class MercantileMasters {

    public static final String MODID = "merchants";
    public static final String NAME = "Mercantile Masters";
    public static final String VERSION = "1.21";

    @Mod.EventHandler
    public void preInit(FMLPreInitializationEvent event) {
        // Initialization code here
    }

    @SubscribeEvent
    public void onPlayerInteract(PlayerInteractEvent.RightClickBlock event) {
        World world = event.getWorld();
        BlockPos pos = event.getPos();
        EntityPlayer player = event.getPlayer();

        if (world.getBlockState(pos).getBlock().isAir(world, pos)) {
            return;
        }

        // Check if the block is a trading post
        if (world.getBlockState(pos).getBlock().getRegistryName().toString().equals("examplemod:trading_post")) {
            handleTrading(event.getWorld(), event.getPos(), event.getPlayer());
        }
    }

    @SubscribeEvent
    public void onLivingUpdate(LivingUpdateEvent event) {
        EntityPlayer player = event.getEntityLiving();
        if (player instanceof EntityPlayer) {
            updateMarketPrices(player);
        }
    }

    private void handleTrading(World world, BlockPos pos, EntityPlayer player) {
        // Logic to handle trading interactions
        ItemStack heldItem = player.getHeldItemMainhand();
        if (!heldItem.isEmpty()) {
            // Perform trade logic
            System.out.println("Player " + player.getName() + " is trading with the merchant at " + pos);
            // Example: Simplified trade logic
            if (heldItem.getItem().getRegistryName().toString().equals("minecraft:diamond")) {
                player.addItemStackToInventory(new ItemStack(net.minecraft.init.Items.GOLD_INGOT, 1));
            }
        }
    }

    private void updateMarketPrices(EntityPlayer player) {
        // Logic to update market prices based on supply and demand
        System.out.println("Updating market prices for player: " + player.getName());
        // Example: Simplified price update logic
        if (player.getHeldItemMainhand().getItem().getRegistryName().toString().equals("minecraft:diamond")) {
            player.sendMessage(new net.minecraft.util.text.TextComponentString("Diamond price increased!"));
        }
    }
}
