@Mod("harvesthaven")
public class HarvestHaven {
    public static final ItemRegistry ITEMS = new ItemRegistry();
    public static final BlockRegistry BLOCKS = new BlockRegistry();

    public HarvestHaven() {
        FMLJavaModLoadingContext.get().getModEventBus().addListener(this::setup);
        FMLJavaModLoadingContext.get().getModEventBus().addListener(this::doClientStuff);

        ITEMS.registerItems();
        BLOCKS.registerBlocks();
    }

    private void setup(final FMLCommonSetupEvent event) {
        // Additional mod setup code
    }

    private void doClientStuff(final FMLClientSetupEvent event) {
        // Client-specific initialization code
    }
}

public class ItemRegistry extends Registry<Item> {
    public ItemRegistry() {
        register("crop_seeds", new Item(new Properties().group(ItemGroup.MISC)));
        register("crop_item", new Item(new Properties().group(ItemGroup.FOOD).food(new Food.Builder().hunger(4).saturation(2f).build())));
    }
}

public class BlockRegistry extends Registry<Block> {
    public BlockRegistry() {
        register("crop_block", new CropBlock());
    }

    private static class CropBlock extends BlockCrops {
        @Override
        protected IItemProvider getSeedsItem() {
            return ITEMS.get("crop_seeds");
        }

        @Override
        protected IItemProvider getCropItem() {
            return ITEMS.get("crop_item");
        }
    }
}
