import net.minecraftforge.fml.common.Mod;
import net.minecraftforge.registries.ObjectHolder;

@Mod("terrea_reliquiae")
public class TerraeReliquiaeMod {
    public static final String MODID = "terrea_reliquiae";

    @ObjectHolder(MODID + ":ancient_fragment")
    public static Item ANCIENT_FRAGMENT;

    public TerraeReliquiaeMod() {
        MinecraftForge.EVENT_BUS.register(this);
    }

    @SubscribeEvent
    public void onRegisterItems(RegistryEvent.Register<Item> event) {
        event.getRegistry().register(new Item(new Item.Properties().group(TerraeReliquiaeItemGroup.INSTANCE)).setRegistryName(MODID, "ancient_fragment"));
    }
}

public class TerraeReliquiaeItemGroup extends ItemGroup {
    public static final TerraeReliquiaeItemGroup INSTANCE = new TerraeReliquiaeItemGroup();

    private TerraeReliquiaeItemGroup() {
        super("terrea_reliquiae");
    }

    @Override
    public ItemStack createIcon() {
        return new ItemStack(TerraeReliquiaeMod.ANCIENT_FRAGMENT);
    }
}
